-- ============================================================
-- Migration 029: 액티비티 배지 전체 재시드 v2
--
-- 변경 내용:
--   P1: 600개 배지 설명 전면 개편 (달성 수치 포함 + 등급별 어조 분리)
--   P2: 트레일러닝 Rare 거리 50km → 25km (고도 재조정)
--   P3: 사이클링 G15 Common 80km → 100km (센추리 라이드 정확 매핑)
--   P3: 걷기 7km 그룹 "무념무상의 발걸음" → "만보의 달인"
--   P3: 로드러닝 비-라운드 Common 수치 조정 (5,8,10,14,16,20,23,25km)
--
-- ⚠️  기존 user_activity_badges 삭제 후 재시드 (022 패턴 동일)
-- ============================================================

DELETE FROM public.user_activity_badges
  WHERE badge_id IN (SELECT id FROM public.badges WHERE type = 'activity');
DELETE FROM public.badges
  WHERE type = 'activity'
    AND id NOT IN (
      SELECT linked_badge_id FROM public.poi WHERE linked_badge_id IS NOT NULL
    );

